import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import './Css/Landing.css';

const Landing = () => {
  const navigate = useNavigate();
  const [games, setGames] = useState([]);
  const [showProfile, setShowProfile] = useState(false);

  // NEW: State for the Carousel
  const [currentIndex, setCurrentIndex] = useState(0);

  useEffect(() => {
    const fetchGames = async () => {
      try {
        const response = await fetch('http://localhost:8000/api/top-games');
        const data = await response.json();
        if (data.status === 'success') {
          setGames(data.games);
        }
      } catch (error) {
        console.error("Database connection failed", error);
      }
    };
    fetchGames();
  }, []);

  const handleLogout = () => navigate('/');
  const handleWishlist = (gameTitle) => alert(`Wishlist function for ${gameTitle} is next!`);

  // --- CAROUSEL NAVIGATION CONTROLS ---
  const nextGame = () => {
    setCurrentIndex((prev) => (prev + 1 < games.length ? prev + 1 : prev));
  };

  const prevGame = () => {
    setCurrentIndex((prev) => (prev - 1 >= 0 ? prev - 1 : prev));
  };

  // Allows scrolling with mouse wheel or trackpad
  const handleWheel = (e) => {
    if (e.deltaY > 50 || e.deltaX > 50) nextGame();
    if (e.deltaY < -50 || e.deltaX < -50) prevGame();
  };

  return (
    <div className="landing-shield">
      {/* HEADER */}
      <header className="dash-header">
        <div className="logo">GAMING<span>HUB</span></div>
        <nav className="dash-nav">
          <span className="active">Home</span>
          <span>Community</span>
        </nav>
        <div className="search-bar">
          <input type="text" placeholder="Search games..." />
        </div>
        <div className="profile-wrapper" onClick={() => setShowProfile(!showProfile)}>
          <div className="avatar">G</div>
          {showProfile && (
            <div className="profile-dropdown">
              <div className="dropdown-item">Profile</div>
              <div className="dropdown-item logout" onClick={handleLogout}>Logout</div>
            </div>
          )}
        </div>
      </header>

      {/* ASYMMETRIC SPLIT HERO */}
      <section className="hero-split">
        <div className="hero-left">
          <h1>Featured<br/>Collection</h1>
          <p>Swipe through the top trending games in the database right now.</p>
        </div>
        <div className="hero-right">
          <img 
            src="https://images.unsplash.com/photo-1542751371-adc38448a05e?q=80&w=1000" 
            alt="Gaming visual" 
            className="hero-image"
          />
        </div>
      </section>

      {/* --- NEW 3D COVER FLOW CAROUSEL --- */}
      <section className="carousel-section" onWheel={handleWheel}>

        {/* Left Arrow */}
        <button className="carousel-arrow left" onClick={prevGame} disabled={currentIndex === 0}>
          &#10094;
        </button>

        <div className="carousel-container">
          {games.map((game, index) => {
            // MATH: Calculate how far this card is from the center card
            const offset = index - currentIndex;
            const absOffset = Math.abs(offset);
            const isCenter = offset === 0;

            // Hide cards that are too far away to improve performance
            if (absOffset > 3) return null;

            return (
              <div 
                key={game.id} 
                className={`carousel-card ${isCenter ? 'active' : ''}`}
                style={{
                  // The 3D Magic: Move it left/right, scale it down, and lower the z-index
                  transform: `translateX(${offset * 160}px) scale(${1 - absOffset * 0.15}) perspective(1000px) rotateY(${offset * -10}deg)`,
                  zIndex: 10 - absOffset,
                  opacity: 1 - absOffset * 0.25,
                }}
                onClick={() => setCurrentIndex(index)} // Clicking a side card brings it to center
              >
                <img src={game.image} alt={game.title} className="carousel-img" />
                <div className="carousel-info">
                  <div>
                    <h3>{game.title}</h3>
                    <span className="genre-badge">{game.genre}</span>
                  </div>
                  <button className="heart-btn" onClick={(e) => { e.stopPropagation(); handleWishlist(game.title); }}>
                    ♥
                  </button>
                </div>
              </div>
            );
          })}
        </div>

        {/* Right Arrow */}
        <button className="carousel-arrow right" onClick={nextGame} disabled={currentIndex === games.length - 1}>
          &#10095;
        </button>

      </section>
    </div>
  );
};

export default Landing;
